export const INLINE_JS = "\r\n        tailwind.config = {\r\n            theme: {\r\n                extend: {\r\n                    colors: {\r\n                        dark: '#09090b',\r\n                        accent: {\r\n                            purple: '#8b5cf6',\r\n                            red: '#ef4444'\r\n                        }\r\n                    },\r\n                    fontFamily: {\r\n                        sans: ['Inter', 'sans-serif'],\r\n                        head: ['Orbitron', 'sans-serif'],\r\n                    }\r\n                }\r\n            }\r\n        }\r\n    \n;\n\r\n        // Init Icons\r\n        lucide.createIcons();\r\n\r\n        // Navbar Scroll Effect\r\n        const navbar = document.getElementById('navbar');\r\n        window.addEventListener('scroll', () => {\r\n            if (window.scrollY > 50) {\r\n                navbar.classList.add('bg-dark/90', 'shadow-2xl');\r\n                navbar.classList.remove('bg-card');\r\n            } else {\r\n                navbar.classList.remove('bg-dark/90', 'shadow-2xl');\r\n            }\r\n        });\r\n\r\n        // Mobile Menu Toggle\r\n        const menuBtn = document.getElementById('menu-btn');\r\n        const closeMenuBtn = document.getElementById('close-menu-btn');\r\n        const mobileMenu = document.getElementById('mobile-menu');\r\n        const mobileLinks = document.querySelectorAll('.mobile-link');\r\n\r\n        function toggleMenu() {\r\n            mobileMenu.classList.toggle('open');\r\n            document.body.classList.toggle('overflow-hidden');\r\n        }\r\n\r\n        menuBtn.addEventListener('click', toggleMenu);\r\n        closeMenuBtn.addEventListener('click', toggleMenu);\r\n        \r\n        mobileLinks.forEach(link => {\r\n            link.addEventListener('click', toggleMenu);\r\n        });\r\n\r\n        // Video Carousel Scroll\r\n        const scrollContainer = document.getElementById('video-scroll-container');\r\n        const scrollLeftBtn = document.getElementById('scroll-left');\r\n        const scrollRightBtn = document.getElementById('scroll-right');\r\n\r\n        scrollLeftBtn.addEventListener('click', () => {\r\n            scrollContainer.scrollBy({ left: -300, behavior: 'smooth' });\r\n        });\r\n        \r\n        scrollRightBtn.addEventListener('click', () => {\r\n            scrollContainer.scrollBy({ left: 300, behavior: 'smooth' });\r\n        });\r\n\r\n    ";

